    .spl-ring-3 { width: 500px; height: 500px; border-color: rgba(108,61,214,0.3); }
    @keyframes spl-ring-out {
      0%   { transform: translate(-50%,-50%) scale(0.1); opacity: 0.9; }
      100% { transform: translate(-50%,-50%) scale(1.8); opacity: 0; }
