html:not(.dark-mode) .alert-card,
html:not(.dark-mode) .subj-card,
html:not(.dark-mode) .perf-stat,
html:not(.dark-mode) .grade-cell,
html:not(.dark-mode) .broadcast-item,
html:not(.dark-mode) .case-card,
html:not(.dark-mode) .note-card,
html:not(.dark-mode) .session-card {
  background: #FFFFFF !important;
  box-shadow: 0 1px 4px rgba(0,0,0,0.04), 0 4px 16px rgba(108,61,214,0.05) !important;
  color: var(--text) !important;
}

/* ── KPI / Stat Cards ── */
html:not(.dark-mode) .kpi-card,
html:not(.dark-mode) .metric-card,
html:not(.dark-mode) .perf-stat {
  background: #FFFFFF !important;
  box-shadow: 0 2px 12px rgba(108,61,214,0.08) !important;
}

/* قيم الأرقام الكبيرة */
html:not(.dark-mode) .stat-value,
html:not(.dark-mode) .kpi-value,
html:not(.dark-mode) .metric-value,
html:not(.dark-mode) .perf-value,
html:not(.dark-mode) .big-num {
  color: #1E293B !important;
}

/* تسميات البطاقات */
html:not(.dark-mode) .stat-label,
html:not(.dark-mode) .kpi-label,
html:not(.dark-mode) .metric-label,
html:not(.dark-mode) .label,
html:not(.dark-mode) .card-label,
html:not(.dark-mode) .kpi-card .kpi-label,
html:not(.dark-mode) .metric-card .label {
  color: #64748B !important;
}

/* الاتجاهات (ارتفع/انخفض) */
html:not(.dark-mode) .stat-trend,
html:not(.dark-mode) .trend-up   { color: #059669 !important; }
html:not(.dark-mode) .trend-down { color: #DC2626 !important; }

/* النصوص العامة داخل البطاقات */
html:not(.dark-mode) .stat-card *,
html:not(.dark-mode) .card *:not([style*="color"]) {
  color: inherit;
}

/* ── جدول الدرجات ── */
html:not(.dark-mode) table {
  background: #FFFFFF !important;
  color: var(--text) !important;
}
html:not(.dark-mode) thead th {
  background: linear-gradient(135deg, #6C3DD6, #22D3EE) !important;
  color: #fff !important;
}
html:not(.dark-mode) tbody tr:nth-child(even) {
  background: rgba(108,61,214,0.03) !important;
}
html:not(.dark-mode) tbody tr:hover {
  background: rgba(108,61,214,0.06) !important;
}

/* ── تقدم الدرجات ── */
html:not(.dark-mode) .grade-bar-wrap,
html:not(.dark-mode) .stars-bar-wrap { background: rgba(0,0,0,0.07) !important; }

/* ── النافبار الجانبي ── */
html:not(.dark-mode) .sidebar,
html:not(.dark-mode) .nav-panel {
  background: var(--sidebar-bg) !important;
  border-color: var(--border) !important;
  backdrop-filter: blur(12px);
}
html:not(.dark-mode) .nav-item { color: var(--text) !important; }
html:not(.dark-mode) .nav-item:hover { background: rgba(108,61,214,0.07) !important; }
html:not(.dark-mode) .nav-item.active {
  background: rgba(108,61,214,0.1) !important;
  color: var(--primary) !important;
}

/* ── التابز ── */
html:not(.dark-mode) .tab { color: var(--muted) !important; }
html:not(.dark-mode) .tab:hover { color: var(--text) !important; }
html:not(.dark-mode) .tab.active {
  color: var(--primary) !important;
  border-bottom-color: var(--primary) !important;
}
html:not(.dark-mode) .tabs { border-bottom-color: var(--border) !important; }

/* ── حالات البطاقات ── */
html:not(.dark-mode) .period-card.current { background: rgba(5,150,105,0.06) !important; }
html:not(.dark-mode) .period-card.next    { background: rgba(14,165,233,0.05) !important; }
html:not(.dark-mode) .tl-dot             { background: var(--bg) !important; }

/* ── أزرار الفلتر ── */
html:not(.dark-mode) .hw-filter-btn,
html:not(.dark-mode) .day-btn,
html:not(.dark-mode) .filter-btn {
  background: #FFFFFF !important;
  border-color: rgba(0,0,0,0.1) !important;
  color: var(--muted) !important;
}
html:not(.dark-mode) .hw-filter-btn.active,
html:not(.dark-mode) .day-btn.active,
html:not(.dark-mode) .filter-btn.active {
  background: var(--primary) !important;
  border-color: var(--primary) !important;
  color: #fff !important;
}

/* ── الإدخالات ── */
html:not(.dark-mode) input,
html:not(.dark-mode) select,
html:not(.dark-mode) textarea {
  background: #FFFFFF !important;
  border-color: rgba(0,0,0,0.12) !important;
  color: var(--text) !important;
}
html:not(.dark-mode) input:focus,
html:not(.dark-mode) select:focus,
html:not(.dark-mode) textarea:focus {
  border-color: var(--primary) !important;
  box-shadow: 0 0 0 3px rgba(108,61,214,0.1) !important;
}

/* ── الأزرار الرئيسية ── */
html:not(.dark-mode) .btn-primary {
  background: var(--primary) !important;
  color: #fff !important;
}
html:not(.dark-mode) .btn-secondary {
  background: #FFFFFF !important;
  border-color: var(--border) !important;
  color: var(--text) !important;
}

/* ── النصوص المساعدة ── */
html:not(.dark-mode) .muted, html:not(.dark-mode) .text-muted { color: var(--muted) !important; }
html:not(.dark-mode) h1, html:not(.dark-mode) h2,
html:not(.dark-mode) h3, html:not(.dark-mode) h4 { color: var(--text) !important; }


/* ══════════════════════ DARK MODE (optional) ══════════════════════ */
html.dark-mode {
  --bg:      #0D1B2A;
  --card:    rgba(255,255,255,0.04);
  --card2:   rgba(255,255,255,0.06);
  --border:  rgba(255,255,255,0.08);
  --text:    #E2E8F0;
  --muted:   #94A3B8;
  --sidebar-bg: rgba(13,27,42,0.95);
}
html.dark-mode, html.dark-mode body {
  background: var(--bg) !important;
  color: var(--text) !important;
}
html.dark-mode .card,
html.dark-mode .period-card,
html.dark-mode .tl-card,
html.dark-mode .stat-card,
html.dark-mode .lesson-card,
html.dark-mode .alert-card,
html.dark-mode .case-card,
html.dark-mode .note-card,
html.dark-mode .student-row,
html.dark-mode .grade-row,
html.dark-mode .session-card {
  background: var(--card) !important;
  box-shadow: 0 1px 8px rgba(0,0,0,0.3) !important;
  color: var(--text) !important;
}
html.dark-mode table { background: transparent !important; color: var(--text) !important; }
html.dark-mode tbody tr:nth-child(even) { background: rgba(255,255,255,0.03) !important; }
html.dark-mode tbody tr:hover { background: rgba(255,255,255,0.06) !important; }
html.dark-mode input, html.dark-mode select, html.dark-mode textarea {
  background: rgba(255,255,255,0.05) !important;
  border-color: var(--border) !important;
  color: var(--text) !important;
}
html.dark-mode .sidebar, html.dark-mode .nav-panel {
  background: var(--sidebar-bg) !important;
}


/* ══════════════════════ زر تبديل الثيم ══════════════════════ */
#theme-toggle-btn {
  position: fixed;
  bottom: 24px;
  left: 24px;
  z-index: 9999;
  width: 44px;
  height: 44px;
  border-radius: 50%;
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 20px;
  box-shadow: 0 4px 16px rgba(0,0,0,0.2);
  transition: all 0.3s ease;
  background: linear-gradient(135deg, #6C3DD6, #22D3EE);
  color: #fff;
}
#theme-toggle-btn:hover {
  transform: scale(1.1);
  box-shadow: 0 6px 20px rgba(108,61,214,0.4);
}

platform-theme-light.css:
/* ═══════════════════════════════════════════════════════════════
   EduOS — Light Theme Override
   يُطبَّق على: بوابة الطالب/ة · بوابة ولي الأمر
   أضف هذا الملف بعد <style> مباشرة في كل صفحة تحتاج الثيم الفاتح
   ═══════════════════════════════════════════════════════════════ */

/* ── 1. متغيرات الألوان الجديدة ── */
:root {
  --bg:       #F8F9FF;
  --card:     #FFFFFF;
  --card2:    #FAFBFF;
  --border:   rgba(0,0,0,0.06);
  --primary:  #6C3DD6;
  --accent:   #0EA5E9;
  --gold:     #D97706;
  --green:    #059669;
  --red:      #DC2626;
  --orange:   #EA580C;
  --text:     #1E293B;
  --muted:    #64748B;
  --pink:     #DB2777;
  --purple:   #7C3AED;
}

/* ── 2. الخلفية العامة والنص ── */
html, body { background: var(--bg) !important; color: var(--text) !important; }

/* ── 3. الهيدر ── */
.header {
  background: linear-gradient(135deg, #6C3DD6 0%, #22D3EE 100%) !important;
  border-bottom: none !important;
  box-shadow: 0 2px 16px rgba(108,61,214,0.18) !important;
}
/* نصوص الهيدر على خلفية ملوّنة → أبيض */
.header .brand-name, .header .brand-sub,
.header .user-name, .header .user-grade,
.header .week-info, .header .stars-badge,
.header .logout-btn, .header .btn-logout,
.header span, .header div { color: #fff !important; }
.header .stars-badge {
  background: rgba(255,255,255,0.18) !important;
  border-color: rgba(255,255,255,0.3) !important;
}
.header .logout-btn, .header .btn-logout {
  border-color: rgba(255,255,255,0.3) !important;
  color: #fff !important;
}
.header .logout-btn:hover, .header .btn-logout:hover {
  background: rgba(255,255,255,0.15) !important;
  border-color: rgba(255,255,255,0.5) !important;
}

/* ── 4. البطاقات العامة ── */
.card, .period-card, .tl-card, .sched-row, .hw-card,
.subj-grade-row, .subj-card, .perf-stat, .stat-card,
.reinf-item, .hw-item, .broadcast-item, .login-card,
.child-card-mini, .uni-path {
  background: #FFFFFF !important;
  box-shadow: 0 1px 6px rgba(0,0,0,0.05), 0 4px 16px rgba(108,61,214,0.06) !important;
}
/* ألوان بوردر الحالة تبقى (current / overdue) */
.period-card.current { background: rgba(5,150,105,0.06) !important; }
.period-card.next    { background: rgba(14,165,233,0.05) !important; }
.hw-card.overdue     { background: rgba(220,38,38,0.04) !important; }
.hw-card.due-today   { background: rgba(217,119,6,0.04) !important; }
.tl-item.current .tl-card { background: rgba(108,61,214,0.07) !important; }
.tl-item.brk .tl-card    { background: rgba(217,119,6,0.05) !important; }
.tl-item.done .tl-card    { opacity: .45 !important; }

/* ── 5. نقطة التايملاين ── */
.tl-dot { background: var(--bg) !important; }

/* ── 6. تقدم الدرجات ── */
.grade-bar-wrap  { background: rgba(0,0,0,0.08) !important; }
.stars-bar-wrap  { background: rgba(0,0,0,0.08) !important; }

/* ── 7. نجوم الهيدر ── */
.stars-badge {
  background: rgba(217,119,6,0.1) !important;
  border-color: rgba(217,119,6,0.25) !important;
}

/* ── 8. زر الخروج ── */
.logout-btn, .btn-logout {
  border-color: rgba(0,0,0,0.1) !important;
  color: var(--muted) !important;
  background: transparent !important;
}
.logout-btn:hover, .btn-logout:hover {
  background: rgba(220,38,38,0.1) !important;
  border-color: var(--red) !important;
  color: var(--red) !important;
}

/* ── 9. التابز ── */
.tab { color: var(--muted) !important; }
.tab:hover { color: var(--text) !important; }
.tab.active { color: var(--accent) !important; border-bottom-color: var(--accent) !important; }
.tabs { border-bottom-color: var(--border) !important; }

/* ── 10. أزرار الفلتر والأيام ── */
.hw-filter-btn, .day-btn {
  background: #FFFFFF !important;
  border-color: rgba(0,0,0,0.1) !important;
  color: var(--muted) !important;
}
.hw-filter-btn.active, .day-btn.active, .day-btn:hover {
  background: var(--primary) !important;
  border-color: var(--primary) !important;
  color: #fff !important;
}
.day-btn.today { border-color: var(--accent) !important; }

/* ── 11. الجانبية (parent) ── */
.sidebar {
  background: rgba(255,255,255,0.8) !important;
  border-left: 1px solid var(--border) !important;
}
#child-switcher { background: rgba(0,0,0,0.03) !important; }
.child-btn { border-color: rgba(0,0,0,0.1) !important; }
.child-btn.active {
  background: rgba(14,165,233,0.12) !important;
  color: var(--accent) !important;
  border-color: rgba(14,165,233,0.35) !important;
}

/* ── 12. عناصر التنقل (parent) ── */
.nav-item { color: var(--muted) !important; }
.nav-item:hover { background: rgba(0,0,0,0.04) !important; color: var(--text) !important; }
.nav-item.active {
  background: rgba(14,165,233,0.1) !important;
  color: var(--accent) !important;
  border-color: rgba(14,165,233,0.25) !important;
}

/* ── 13. الجداول ── */
.sch-table th { background: rgba(0,0,0,0.03) !important; color: var(--muted) !important; }
.sch-table td,
.data-table td { border-bottom: 1px solid rgba(0,0,0,0.05) !important; }
.data-table tr:hover td { background: rgba(0,0,0,0.02) !important; }
.sch-now { background: rgba(14,165,233,0.07) !important; }

/* ── 14. المحادثة الذكية ── */
.chat-msg.ai {
  background: #F1F5F9 !important;
  border-color: rgba(0,0,0,0.07) !important;
  color: var(--text) !important;
}
.chat-msg.user {
  background: linear-gradient(135deg, rgba(14,165,233,0.1), rgba(124,58,237,0.1)) !important;
  border-color: rgba(14,165,233,0.2) !important;
  color: var(--text) !important;
}
.chat-input {
  background: #FFFFFF !important;
  border-color: rgba(0,0,0,0.1) !important;
  color: var(--text) !important;
}
.chat-input::placeholder { color: var(--muted) !important; }
.quick-btn {
  background: #FFFFFF !important;
  border-color: rgba(0,0,0,0.09) !important;
  color: var(--text) !important;
}
.quick-btn:hover { background: rgba(14,165,233,0.08) !important; border-color: var(--accent) !important; }

/* ── 15. شريط الإشعارات (ticker) ── */
.ticker {
  background: rgba(238,242,250,0.97) !important;
  border-top: 1px solid var(--border) !important;
}
.ticker-label { background: var(--accent) !important; color: #fff !important; }
.ticker-inner { color: var(--muted) !important; }

/* ── 16. حقول تسجيل الدخول ── */
.form-group input {
  background: #FFFFFF !important;
  border-color: rgba(0,0,0,0.1) !important;
  color: var(--text) !important;
}
.form-group input:focus { border-color: var(--accent) !important; }
.form-group input::placeholder { color: var(--muted) !important; }
#login-screen { background: var(--bg) !important; }
.login-card {
  background: #FFFFFF !important;
  border-color: rgba(0,0,0,0.06) !important;
  box-shadow: 0 8px 40px rgba(0,0,0,0.12) !important;
}

/* ── 17. الـ Alert items ── */
.alert-item.hw   { background: rgba(14,165,233,0.06) !important; border-color: rgba(14,165,233,0.18) !important; }
.alert-item.exam { background: rgba(220,38,38,0.05) !important; border-color: rgba(220,38,38,0.18) !important; }

/* ── 18. النافذة المنبثقة (Live Lesson Banner) ── */
#live-lesson-banner {
  background: linear-gradient(135deg, rgba(220,38,38,0.1), rgba(220,38,38,0.04)) !important;
}

/* ── 19. الـ Spinner ── */
.spinner { border-color: rgba(0,0,0,0.08) !important; border-top-color: var(--accent) !important; }

/* ── 20. الـ Toast ── */
#toast { backdrop-filter: blur(8px); }

/* ── 21. Scrollbar ── */
::-webkit-scrollbar { width: 5px; height: 5px; }
::-webkit-scrollbar-track { background: rgba(0,0,0,0.03); }
::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.15); border-radius: 3px; }

/* ── 22. Uni path + Stars hero ── */
.uni-path {
  background: linear-gradient(135deg, rgba(108,61,214,0.08), rgba(14,165,233,0.05)) !important;
  border-color: rgba(108,61,214,0.2) !important;
}
.stars-hero {
  background: linear-gradient(135deg, rgba(217,119,6,0.08), rgba(217,119,6,0.03)) !important;
  border-color: rgba(217,119,6,0.2) !important;
}

/* ── 23. الـ Rank badge ── */
.rank-badge {
  background: rgba(217,119,6,0.1) !important;
  border-color: rgba(217,119,6,0.25) !important;
}

/* ── 24. nav-label ── */
.nav-label { color: var(--muted) !important; }
.brand-sub, .user-grade, .child-grade-mini { color: var(--muted) !important; }

/* ── 25. Section titles ── */
.section-title { color: var(--primary) !important; }

platform-theme-toggle.js:
/* ═══════════════════════════════════════════════════════════
   EduOS — Theme Toggle (Light ↔ Dark) v2
   للمعلم/ة والمختص/ة — الافتراضي فاتح، مع خيار داكن
   الإصلاح: يُعيد تعيين CSS variables عند التبديل للفاتح
   ═══════════════════════════════════════════════════════════ */
(function() {
  'use strict';

  const STORAGE_KEY = 'eduos_teacher_theme';
  let isDark = sessionStorage.getItem(STORAGE_KEY) === 'dark';

  const LIGHT_VARS = {
    '--bg':           '#F4F6FB',
    '--surface':      '#FFFFFF',
    '--surface2':     '#F0F2FA',
    '--surface3':     '#E8EBF5',
    '--sidebar-bg':   '#FFFFFF',
    '--card':         '#FFFFFF',
    '--card2':        '#F9FAFF',
    '--card-hover':   '#F0F4FF',
    '--text':         '#1E293B',
    '--text2':        '#334155',
    '--text3':        '#475569',
    '--muted':        '#64748B',
    '--border':       'rgba(0,0,0,0.08)',
    '--divider':      'rgba(0,0,0,0.06)',
    '--primary':      '#6C3DD6',
    '--primary2':     '#22D3EE',
    '--accent':       '#0EA5E9',
    '--green':        '#059669',
    '--red':          '#DC2626',
    '--yellow':       '#D97706',
    '--purple':       '#7C3AED',
    '--orange':       '#EA580C',
    '--input-bg':     '#F8FAFF',
    '--input-border': 'rgba(108,61,214,0.2)',
    '--shadow':       '0 2px 12px rgba(0,0,0,0.06)',
    '--shadow2':      '0 4px 20px rgba(0,0,0,0.08)',
    '--glow-indigo':  'rgba(108,61,214,0.06)',
  };

  const DARK_VARS = {
    '--bg':           '#0D1B2A',
    '--surface':      '#111827',
    '--surface2':     '#1a2235',
    '--surface3':     '#1f2d44',
    '--sidebar-bg':   'rgba(13,27,42,0.95)',
    '--card':         'rgba(255,255,255,0.04)',
    '--card2':        'rgba(255,255,255,0.06)',
    '--card-hover':   'rgba(255,255,255,0.08)',
    '--text':         '#E2E8F0',
    '--text2':        '#CBD5E1',
    '--text3':        '#94A3B8',
    '--muted':        '#94A3B8',
    '--border':       'rgba(255,255,255,0.08)',
    '--divider':      'rgba(255,255,255,0.06)',
    '--primary':      '#818CF8',
    '--primary2':     '#22D3EE',
    '--accent':       '#38BDF8',
    '--green':        '#34D399',
    '--red':          '#F87171',
    '--yellow':       '#FCD34D',
    '--purple':       '#A78BFA',
    '--orange':       '#FB923C',
    '--input-bg':     'rgba(255,255,255,0.05)',
    '--input-border': 'rgba(255,255,255,0.12)',
    '--shadow':       '0 2px 12px rgba(0,0,0,0.4)',
    '--shadow2':      '0 4px 20px rgba(0,0,0,0.5)',
    '--glow-indigo':  'rgba(99,102,241,0.12)',
  };

  function applyVars(vars) {
    const r = document.documentElement;
    Object.entries(vars).forEach(([k, v]) => r.style.setProperty(k, v));
  }

  function applyTheme() {
    const r = document.documentElement;
    if (isDark) {
      r.classList.add('dark-mode');
      applyVars(DARK_VARS);
      document.body && (document.body.style.background = '#0D1B2A');
      document.body && (document.body.style.color = '#E2E8F0');
      if (btn) { btn.textContent = '☀️'; btn.title = 'الثيم الفاتح | Light Mode'; }
      sessionStorage.setItem(STORAGE_KEY, 'dark');
    } else {
      r.classList.remove('dark-mode');
      applyVars(LIGHT_VARS);
      document.body && (document.body.style.background = '#F4F6FB');
      document.body && (document.body.style.color = '#1E293B');
      if (btn) { btn.textContent = '🌙'; btn.title = 'الثيم الداكن | Dark Mode'; }
      sessionStorage.setItem(STORAGE_KEY, 'light');
    }
  }

  // تطبيق فوري قبل DOMContentLoaded لتجنب الوميض
  applyVars(isDark ? DARK_VARS : LIGHT_VARS);
  if (isDark) document.documentElement.classList.add('dark-mode');
  else document.documentElement.classList.remove('dark-mode');

  let btn = null;

  function injectButton() {
    if (document.getElementById('theme-toggle-btn')) return;
    btn = document.createElement('button');
    btn.id = 'theme-toggle-btn';
    btn.textContent = isDark ? '☀️' : '🌙';
    btn.title = isDark ? 'الثيم الفاتح | Light Mode' : 'الثيم الداكن | Dark Mode';
    btn.setAttribute('aria-label', 'تبديل الثيم');
    btn.onclick = function() {
      isDark = !isDark;
      applyTheme();
    };
    document.body.appendChild(btn);
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', function() {
      injectButton();
      applyTheme(); // تأكيد تطبيق body styles
    });
  } else {
    injectButton();
    applyTheme();
  }
})();

